INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-a3078d07-moex-00176', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '習近平2019年1月2日在《告臺灣同胞書》40週年紀念會上，提出對臺五大政策（簡稱《習五點》），至 今仍然是中共目前對臺政策最重要的指導方針。下列何者不是《習五點》的內容？', '["習近平定義何謂「九二共識」：「70年來，我們秉持求同存異精神，推動兩岸雙方在一個中國的基礎 上達成兩岸同屬一個中國，共同努力謀求國家統一的九二共識」", "探索「一國兩制臺灣方案」，豐富和平統一實踐", "中國人不打中國人，……，我們不承諾放棄使用武力，保留採取一切必要措施的選項", "接受「一中各表」的九二共識，來推動兩岸的和平統一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00177', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '近年來兩岸經濟關係的變化，下列敘述何者錯誤？', '["臺商對中國大陸投資占海外投資比率，在2010年曾飆升至83.8%的高點，到2022年則大幅下降、占 投資總額34%，到了2023年更降至11.4%、創30年新低", "2022年我國出口至中國大陸的貿易額，ECFA相關貨品占了約2,000億元，占整體貿易額5,000億元的 大概40%左右，亦使北京以ECFA相關貨品的禁運來脅迫臺灣，可以對臺灣經濟構成重大傷害", "2020年對中、港、澳出口占臺灣出口比重43.9%，到了2024年1至4月比重下降到30.7%，這是過去22 年來同季最低", "2024年1至4月臺灣對美國出口占總出口比重則上升到22.3%，對東協升至20.2%，分別是24年來以及 歷年同季的最高水準。主因自2018年後美中貿易戰開展以來，臺灣企業在美國客戶的督促下，一直 在實現生產地多元化，部分集中在中國大陸的產能，轉移到臺灣、美國、東南亞等地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00178', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '臺灣面臨中共對臺複合性施壓，為了展現守護國家的決心，賴清德總統提出「和平四大支柱行動方案」， 下列何者不是其中的方案？', '["談判兩岸軍事互信機制與和平協議", "強化國防和不對稱戰力，建立臺灣的嚇阻力量", "深化與國際社會和民主國家的合作關係", "強化經濟安全和供應鏈的韌性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00179', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '2022年10月中國共產黨召開第二十次全國代表大會（簡稱中共二十大），下列敘述何者錯誤？', '["二十大習近平的《政治報告》中，自2002年中共十六大之後，再次出現「不承諾放棄使用武力」來 處理臺灣問題。十七至十九屆《政治報告》均未提及「不承諾放棄使用武力」此語", "7位中共政治局常委全是「習近平派」，習近平權力一把抓", "習近平在二十大上破例連任第三屆中共總書記，打破鄧小平時代以來只做兩屆10年的慣例", "習近平在二十大上，延續慣例做了5年後二十一大的接班人安排，承諾不會爭取第四個任期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00180', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關臺灣地區與大陸地區人民關係條例相關規定，下列敘述何者錯誤？', '["該條例關於大陸地區人民之規定，於大陸地區人民旅居國外者，不適用之", "大陸委員會統籌處理有關大陸事務，為本條例之主管機關", "該條例第1條第一句話是：「國家統一前」", "行政院得設立或指定機構，處理兩岸人民往來有關之事務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00181', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '近年來與中共有明顯海上衝突的國家，是下列那兩個？', '["日本與菲律賓", "日本與新加坡", "菲律賓與馬來西亞", "馬來西亞與泰國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00182', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關中共僑務工作的敘述何者錯誤？', '["最高主管單位是國務院僑務辦公室，簡稱「國僑辦」", "中共各省、市、自治區都設有僑務工作相關辦公室", "中共僑務工作為「國僑辦」所專屬，外交部並不負責", "「國僑辦」在2018年併入中共中央統一戰線工作部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00183', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關中共「一帶一路」的敘述，下列何者錯誤？', '["是中共總書記胡錦濤在2013年提出，協助外國進行基礎建設", "全名是「絲綢之路經濟帶」與「21世紀海上絲綢之路」", "搭配成立「亞洲基礎設施投資銀行」以提供外國貸款", "義大利在2023年宣布退出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00184', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '對於「海協會」的敘述，下列何者錯誤？', '["全名是海峽兩岸關係協會", "是中共處理兩岸事務的單位，對口單位是我國的財團法人海峽交流基金會", "為一民間機構，不受中共黨政機關所控制", "現任會長是張志軍，為前任國台辦主任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00185', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '賴清德總統在2024年5月就職演說中，強調會堅守蔡英文前總統在2021年提出的「四個堅持」。下列何 者非「四個堅持」的內容？', '["永遠堅持自由民主的憲政體制", "堅持中華民國與中華人民共和國互不隸屬", "堅持中華民國臺灣的前途，必須遵循全體臺灣人民的意志", "堅持臺灣主權獨立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
